using Microsoft.Extensions.DependencyInjection; using Microsoft.Extensions.Hosting; using Microsoft.Extensions.Logging;
namespace Expenses.Persistence.Seed; /** <summary>Expense seed host.</summary> */ public sealed class ExpensesSeedHostedService(IServiceProvider services,ILogger<ExpensesSeedHostedService> logger):IHostedService{/** <inheritdoc/> */ public async Task StartAsync(CancellationToken ct){try{using var scope=services.CreateScope();await ExpensesSeeder.SeedAsync(scope.ServiceProvider.GetRequiredService<ExpensesDbContext>(),ct);logger.LogInformation("Expenses seed completed.");}catch(Exception ex){logger.LogWarning(ex,"Expenses seed skipped.");}}/** <inheritdoc/> */ public Task StopAsync(CancellationToken ct)=>Task.CompletedTask;}
